const workflows = $('Fetch Week Performance').all().map(i => i.json);
const analytics = $('Fetch Business Metrics').all().map(i => i.json);

const summary = {
  total_runs: workflows.reduce((s, w) => s + parseInt(w.runs), 0),
  avg_success_rate: (workflows.reduce((s, w) => s + parseFloat(w.success_rate), 0) / workflows.length * 100).toFixed(1),
  worst_workflow: workflows.sort((a,b) => parseFloat(a.success_rate) - parseFloat(b.success_rate))[0],
  best_workflow: workflows.sort((a,b) => parseFloat(b.success_rate) - parseFloat(a.success_rate))[0],
  slowest_workflow: workflows.sort((a,b) => parseFloat(b.avg_duration) - parseFloat(a.avg_duration))[0],
  workflows,
  analytics,
  week_ending: new Date().toISOString().split('T')[0]
};
return summary;

const response = $input.item.json;
